<?php
namespace App\Domain\Inventory;
use App\Domain\Inventory\Capacity\InventorySlotCalculator;use App\Domain\Inventory\Capacity\PendingRewardCapacityService;use App\Models\Character;use App\Models\Item;use Carbon\CarbonImmutable;use InvalidArgumentException;
final class CharacterInventorySummaryService{private $inventory;private $slots;private $capacity;public function __construct(InventoryService $inventory,InventorySlotCalculator $slots,PendingRewardCapacityService $capacity){$this->inventory=$inventory;$this->slots=$slots;$this->capacity=$capacity;}public function snapshot(Character $character,CarbonImmutable $now=null){$entries=$this->inventory->entries($character);$ids=$entries->map(function($entry){return$entry->itemId();})->unique()->values();$items=$ids->isEmpty()?collect():Item::whereIn('id',$ids)->get()->keyBy('id');$rows=[];foreach($entries as $entry){$item=$items->get($entry->itemId());if(!$item||(int)$entry->totalQuantity()<=0||(int)$item->max_stack<1)throw new InvalidArgumentException('Invalid inventory summary state.');$used=$this->slots->calculate([['item_id'=>(int)$item->id,'quantity'=>(int)$entry->totalQuantity(),'max_stack'=>(int)$item->max_stack]])->slots();$rows[]=['item_id'=>(int)$item->id,'item_code'=>$item->code,'item_name'=>$item->name,'quantity'=>(int)$entry->totalQuantity(),'locked_quantity'=>(int)$entry->lockedQuantity(),'available_quantity'=>(int)$entry->availableQuantity(),'max_stack'=>(int)$item->max_stack,'used_slots'=>$used];}usort($rows,function($a,$b){$name=strcmp($a['item_name'],$b['item_name']);return$name!==0?$name:$a['item_id']<=>$b['item_id'];});$capacity=$this->capacity->snapshot($character,$now?:CarbonImmutable::now())->toArray();return['inventory_items'=>$rows,'inventory_status'=>['effective_capacity'=>$capacity['effective_capacity'],'current_used_slots'=>$capacity['current_used_slots'],'current_free_slots'=>$capacity['current_free_slots']],'pending_projection'=>['projected_used_slots'=>$capacity['projected_used_slots'],'projected_free_slots'=>$capacity['projected_free_slots'],'claim_fits'=>$capacity['claim_fits'],'missing_slots_for_claim'=>$capacity['missing_slots_for_claim'],'effective_reserve'=>$capacity['effective_reserve'],'hunting_can_continue'=>$capacity['hunting_can_continue']]];}}
